mapper.select:
SELECT s.id, s.name, s.lat, s.lng, s.category, TIME_FORMAT(s.close_time, '%H:%i') AS close_time, s.thumbnail_url, SUM(i.stock) AS total_stock, MIN(i.discount_price) AS min_discount_price, MIN(i.original_price) AS min_original_price, MAX(i.discount_rate) AS max_discount_rate,
(6371 * ACOS( COS(RADIANS(#{f.centerLat})) * COS(RADIANS(s.lat)) * COS(RADIANS(s.lng) - RADIANS(#{f.centerLng})) + SIN(RADIANS(#{f.centerLat})) * SIN(RADIANS(s.lat)) ))
NULL
AS distance_km FROM stores s INNER JOIN items i ON i.store_id = s.id
s.deleted_at IS NULL AND i.deleted_at IS NULL AND i.stock > 0 AND i.expire_at > NOW()
AND s.lat BETWEEN #{bbox.minLat} AND #{bbox.maxLat} AND s.lng BETWEEN #{bbox.minLng} AND #{bbox.maxLng}
AND s.category = #{f.category}
AND i.discount_rate >= #{f.minDiscountRate}
AND i.discount_rate <= #{f.maxDiscountRate}
AND i.discount_price <= #{f.maxDiscountPrice}
AND i.expire_at <= DATE_ADD(NOW(), INTERVAL #{f.expireWithinMinutes} MINUTE)
GROUP BY s.id, s.name, s.lat, s.lng, s.category, s.close_time, s.thumbnail_url
ORDER BY max_discount_rate DESC, total_stock ASC
ORDER BY distance_km ASC, total_stock ASC
ORDER BY total_stock ASC, min_discount_price ASC

